#include <bits/stdc++.h>
using namespace std;
long long n,m,b,x,y,L[4000005],R[4000005];
double sum[4000005],fang[4000005],a[4000005],lazy[4000005],k;
void pushdown(long long p){
	lazy[p*2]+=lazy[p];
	lazy[p*2+1]+=lazy[p];
	fang[p*2]+=lazy[p]*lazy[p]*(R[p*2]-L[p*2]+1)+2*sum[p*2]*lazy[p];
	fang[p*2+1]+=lazy[p]*lazy[p]*(R[p*2+1]-L[p*2+1]+1)+2*sum[p*2+1]*lazy[p];
	sum[p*2]+=lazy[p]*(R[p*2]-L[p*2]+1);
	sum[p*2+1]+=lazy[p]*(R[p*2+1]-L[p*2+1]+1);
	lazy[p]=0;
}
void build(long long p,long long l,long long r){
	L[p]=l;
	R[p]=r;
	if(l==r){
		fang[p]=a[r]*a[r];
		sum[p]=a[r];
		return;
	}
	long long mid=(r-l)/2+l;
	build(p*2,l,mid);
	build(p*2+1,mid+1,r);
	sum[p]=sum[p*2]+sum[p*2+1];
	fang[p]=fang[p*2]+fang[p*2+1];
}
double CHA2(long long p,long long l,long long r){//查询 
	if(L[p]>=l&&R[p]<=r){
		return fang[p];
	}
	long long mid=(R[p]-L[p])/2+L[p];
	double res=0;
	pushdown(p);
	if(l<=mid)res+=CHA2(p*2,l,r);
	if(r>mid)res+=CHA2(p*2+1,l,r);
	return res;
}
double CHA(long long p,long long l,long long r){//查询 
	if(L[p]>=l&&R[p]<=r){
		return sum[p];
	}
	long long mid=(R[p]-L[p])/2+L[p];
	double res=0;
	pushdown(p);
	if(l<=mid)res+=CHA(p*2,l,r);
	if(r>mid)res+=CHA(p*2+1,l,r);
	return res;
}
void add(long long p,long long l,long long r,double val){
	pushdown(p);
	if(L[p]>=l&&R[p]<=r){
		fang[p]+=val*val*(R[p]-L[p]+1)+2*sum[p]*val;
		sum[p]+=val*(R[p]-L[p]+1);
		lazy[p]+=val;
		return;
	}
	long long mid=(R[p]-L[p])/2+L[p];
	if(l<=mid)add(p*2,l,r,val);
	if(r>mid)add(p*2+1,l,r,val);
	sum[p]=sum[p*2]+sum[p*2+1];
	fang[p]=fang[p*2]+fang[p*2+1];
	return;
}
