int n,m,op,a,b,d[10000002];
inline int read(){
	int x=0,f=1;char ch=getchar();
	while (ch<'0'||ch>'9'){if (ch=='-') f=-1;ch=getchar();}
	while (ch>='0'&&ch<='9'){x=x*10+ch-48;ch=getchar();}
	return x*f;
}
void JIA(int A,int B){//加 
	while(A<=n){
		d[A]++;
		A+=A&-A;
	}
	while(B<=n){
		d[B]--;
		B+=B&-B;
	}
}
int CHA(int A){//查 
	int sum = 0;
	while (A >= 1) {
		sum += d[A];
		A -= A & -A;
	}
	return sum;
}
int main(){
