		inv[i]=ksm(a[i],mod-2);
		if(i>3)d[i]=(i-1)*(d[i-1]+d[i-2])%mod;
	}
}
ll C(ll n,ll m){
	return a[n]*inv[m]%mod*inv[n-m]%mod;
}
