long long n,q,x,y,u,v,deep[500002],st[500002][21];
vector<long long>vec[500001];
void down(long long K){
	for(int i=0;i<vec[K].size();i++){
		if(st[vec[K][i]][0]==0){
			deep[vec[K][i]]=deep[K]+1;
			st[vec[K][i]][0]=K;
			down(vec[K][i]);
		}
	}
}
int LCA(long long x,long long y){
	if(x==y)return x;
	if(deep[x]<deep[y])swap(x,y);
	while(deep[x]>deep[y]){
		x=st[x][min(20,int(log2(deep[x]-deep[y])))];
	}
	if(x==y){
		return x;
	}
	for(int i=20;i>=0;i--){
		if(st[x][i]!=st[y][i]){
			x=st[x][i];
			y=st[y][i];
		}
	}
	return st[x][0];
}
