long long n,mod,m,b,x,y,k,L[4000005],R[4000005],sum[4000005],a[4000005],lazy_add[4000005],lazy_cheng[4000005];
void pushdown(long long p){
	sum[p*2]=(sum[p*2]*lazy_cheng[p]%mod+lazy_add[p]*(R[p*2]-L[p*2]+1)%mod);
	sum[p*2]%=mod;
	sum[p*2+1]=(sum[p*2+1]*lazy_cheng[p]%mod+lazy_add[p]*(R[p*2+1]-L[p*2+1]+1)%mod);
	sum[p*2+1]%=mod;
	
	lazy_cheng[p*2]*=lazy_cheng[p];
	lazy_cheng[p*2]%=mod;
	lazy_add[p*2]*=lazy_cheng[p];
	lazy_add[p*2]%=mod;
	lazy_cheng[p*2+1]*=lazy_cheng[p];
	lazy_cheng[p*2+1]%=mod;
	lazy_add[p*2+1]*=lazy_cheng[p];
	lazy_add[p*2+1]%=mod;
	
	lazy_add[p*2]+=lazy_add[p];
	lazy_add[p*2]%=mod;
	lazy_add[p*2+1]+=lazy_add[p];
	lazy_add[p*2+1]%=mod;
	
	lazy_add[p]=0;
	lazy_cheng[p]=1;
}
void build(long long p,long long l,long long r){
	L[p]=l;
	R[p]=r;
	lazy_cheng[p]=1;
	if(l==r){
		sum[p]=a[r]%mod;
		return;
	}
	long long mid=(r-l)/2+l;
	build(p*2,l,mid);
	build(p*2+1,mid+1,r);
	sum[p]=sum[p*2]+sum[p*2+1];
	sum[p]%=mod;
}
long long CHA(long long p,long long l,long long r){//查询 
	pushdown(p);
	if(L[p]>=l&&R[p]<=r){
		return sum[p]%mod;
	}
	long long mid=(R[p]-L[p])/2+L[p],res=0;
	if(l<=mid)res+=CHA(p*2,l,r);
	if(r>mid)res+=CHA(p*2+1,l,r);
	return res%mod;
}
void add(long long p,long long l,long long r,long long val){
	pushdown(p);
	if(L[p]>=l&&R[p]<=r){
		sum[p]+=val*(R[p]-L[p]+1);
		sum[p]%=mod;
		lazy_add[p]+=val;
		return;
	}
	long long mid=(R[p]-L[p])/2+L[p];
	if(l<=mid)add(p*2,l,r,val);
	if(r>mid)add(p*2+1,l,r,val);
	sum[p]=sum[p*2]+sum[p*2+1];
	sum[p]%=mod;
	return;
}
void cheng(long long p,long long l,long long r,long long val){
	pushdown(p);
	if(L[p]>=l&&R[p]<=r){
		sum[p]*=val;
		sum[p]%=mod;
		lazy_cheng[p]*=val;
		return;
	}
	long long mid=(R[p]-L[p])/2+L[p];
	if(l<=mid)cheng(p*2,l,r,val);
	if(r>mid)cheng(p*2+1,l,r,val);
	sum[p]=sum[p*2]+sum[p*2+1];
	sum[p]%=mod;
	return;
}
