	cin>>n>>mod;
	for(int i=1;i<=n;i++)cin>>a[i];
	build(1,1,n);
	cin>>m;
	for(int l=1;l<=m;l++){
		cin>>b;
		if(b==1){
			cin>>x>>y>>k;
			cheng(1,x,y,k);
		}
		else if(b==2){
			cin>>x>>y>>k;
			add(1,x,y,k);
		}
		else{
			cin>>x>>y;
			cout<<CHA(1,x,y)<<'\n';
		}
	}
	return 0;
}

