		cin>>a[i];
		a[i+n]=a[i];
	}
	for(int i=1;i<=2*n;i++){
		sum[i]+=a[i]+sum[i-1];
		for(int l=1;l<=2*n;l++){
			dp[i][l]=9999999;
		}
		dp[i][i]=0;
	}
	for(int i=2;i<=n;i++){//长度 
		for(int l=1;l<=2*n-i+1;l++){//起点 
			int k=l+i-1;
			for(int j=l;j<k;j++){//分割点 
				dp[l][k]=min(dp[l][k],dp[l][j]+dp[j+1][k]+sum[k]-sum[l-1]);
				dp2[l][k]=max(dp2[l][k],dp2[l][j]+dp2[j+1][k]+sum[k]-sum[l-1]);
			}
		}
	}
	for(int i=1;i<=n;i++){
		maxx=max(maxx,dp2[i][i+n-1]);
		minn=min(minn,dp[i][i+n-1]);
	}
