#include<bits/stdc++.h>
using namespace std;
#define ll long long
ll n,t,q;
ll L[400005],R[400005],lazy[400005];
bitset<32>col[400005];
void build(ll k,ll l,ll r){
	L[k]=l;R[k]=r;
	col[k][1]=1;
	lazy[k]=-1;
	if(l==r)return;
	ll mid=(l+r)/2;
	build(k*2,l,mid);
	build(k*2+1,mid+1,r);
}
void update(ll k){
	if(lazy[k]!=-1){
		lazy[k*2]=lazy[k];
		lazy[k*2+1]=lazy[k];
		col[k*2].reset();
		col[k*2+1].reset();
		col[k*2][lazy[k]]=1;
		col[k*2+1][lazy[k]]=1;
		lazy[k]=-1;
	}
}
void paint(ll k,ll l,ll r,ll v){
	if(L[k]>=l&&R[k]<=r){
		lazy[k]=v;
		col[k].reset();
		col[k][v]=1;
		return;
	}
	update(k);
	ll mid=(L[k]+R[k])/2;
	if(l<=mid)paint(k*2,l,r,v);
	if(r>=mid+1)paint(k*2+1,l,r,v);
	col[k]=col[k*2]|col[k*2+1];
}
bitset<32> cha(ll k,ll l,ll r){
	if(L[k]>=l&&R[k]<=r){
		return col[k];
	}
	update(k);
	ll mid=(L[k]+R[k])/2;
	bitset<32>res;
	res.reset();
	if(l<=mid)res|=cha(k*2,l,r);
	if(r>=mid+1)res|=cha(k*2+1,l,r);
	return res;
}
int main(){
	ios::sync_with_stdio(false);
	cin>>n>>t>>q;
	build(1,1,n);
	for(int i=1;i<=q;i++){
		char ch;
		cin>>ch;
		if(ch=='C'){
			ll l,r,c;
			cin>>l>>r>>c;
			if(l>r)swap(l,r);
			paint(1,l,r,c);
		}
		else{
			ll l,r;
			cin>>l>>r;
			if(l>r)swap(l,r);
			cout<<cha(1,l,r).count()<<'\n';
		}
	}
	return 0;
}

