long long DP(int L,int R,int pos){
	if(L==R&&R==m){
		return 0;
	}
	else if(L==R)return 999999999;
	if(dp[L][R][pos]!=-1)return dp[L][R][pos];
	if(pos){
		dp[L][R][1]=min(DP(L,R-1,0)+(light[R].dis-light[L].dis)*(sum[n]-(sum[R-1]-sum[L-1])),
