int exgcd(int a,int b,int &s,int &t){
	if(b==0){
		s=1;
		t=0;
		return a;
	}
	ll d=exgcd(b,a%b,s,t);
	ll tmp=s;
	s=t;
	t=tmp-a/b*t;
	return d;
}
int product_inverse(int a,int p){
	int s,t;
	exgcd(a,p,s,t);
	return(s%p+p)%p;
}
