	ll a,b;
}a[1000002],d[1000002];
bool cmp(A B,A C){
	return B.a<C.a;
}
bool cmp2(A B,A C){
	if(B.a-B.b==C.a-C.b)return B.a<C.a;
	return B.a-B.b<C.a-C.b;
}
int main(){
	ios::sync_with_stdio(false);
	cin>>n>>m;
	for(int i=1;i<=n;i++){cin>>a[i].a;}
