		if(a[i].a!=a[i-1].a)d[p2++]=a[i];
	}
	sort(d+1,d+p2,cmp);
	ll la=1,p3=2;
	a[1]=d[1];
	for(int i=2;i<p2;i++){
		if(d[i].a-d[i].b<d[la].a-d[la].b){
