    	cin>>x;
    	cnt=0;mi=0;v=0;jl=0;cnt2=0;m2=0;
    	while(mi<k&&v<x-1){
    		v++;
    		cnt++;
    		mi+=v;
		}
		k2=k-mi;
		while(mi+m2<k){
			if(k2-2*m2>=v+1)v++;
			else{
				cout<<cnt+2*cnt2+ceil(1.0*max((ll)0,(k2-2*m2))/v)<<'\n';
